import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';

const client = new BedrockAgentRuntimeClient({ region: 'us-east-1' });

const AGENT_ID = 'YOUR_AGENT_ID';
const AGENT_ALIAS_ID = 'YOUR_AGENT_ALIAS_ID';

export async function invokeContentAgent(request: string, sessionId: string): Promise<string> {
  const command = new InvokeAgentCommand({
    agentId: AGENT_ID,
    agentAliasId: AGENT_ALIAS_ID,
    sessionId,
    inputText: request,
    sessionState: { promptSessionState: { traceEnabled: true } },
    enableTrace: true
  });

  const response = await client.send(command);
  let content = '';
  for await (const chunk of response.completion!) {
    if (chunk.bytes) {
      content += new TextDecoder().decode(chunk.bytes);
    }
  }
  return content.trim();
}

