import { verify, Policy } from 'vex-sdk';

export async function verifiedMultiTurnContent(request: string, sessionId: string, prevContent?: string) {
  const content = await invokeContentAgent(request, sessionId);

  const policies = [
    Policy.brandConsistency(),
    Policy.toneAdherence('professional'),
    Policy.sessionContinuity({ previousContent: prevContent }),
    Policy.factualAccuracy()
  ];

  const result = await verify({
    content,
    policies,
    context: { sessionId, request, turn: 2 }
  });

  return {
    content,
    passed: result.passed,
    issues: result.issues,
    confidence: result.score
  };
}

def validate_action_group_response(action_output: dict) -> bool:
    schema_policy = Policy.json_schema({
        'type': 'object',
        'required': ['facts_verified', 'sources', 'content_snippet'],
        'properties': {
            'facts_verified': {'type': 'boolean'},
            'sources': {'type': 'array'},
            'confidence': {'type': 'number', 'minimum': 0, 'maximum': 1}
        }
    })

    result = verify(action_output, policies=[schema_policy])
    return result.passed
